  "requestFramePermissions": []
}

export interface Officer {
  id: string;
  unit: string;
  rank: string;
  name: string;
  contact: string;
  category: string;
  role?: string;
}

export interface CategoryGroup {
  id: string;
  label: string;
  icon: string;
}

import React from 'react';
import { Officer } from '../types';

interface OfficerCardProps {
  officer: Officer;
}

const OfficerCard: React.FC<OfficerCardProps> = ({ officer }) => {
  const handleCall = () => {
    window.location.href = `tel:${officer.contact.replace(/\s|-/g, '')}`;
  };

  const handleWhatsApp = () => {
    const cleanPhone = officer.contact.replace(/\s|-/g, '');
    const phone = cleanPhone.length === 9 ? `5582${cleanPhone}` : `55${cleanPhone}`;
    window.open(`https://wa.me/${phone}`, '_blank');
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow group">
      <div className="p-4 sm:p-5">
        <div className="flex justify-between items-start mb-2">
          <span className="text-xs font-bold uppercase tracking-wider text-blue-600 bg-blue-50 px-2 py-1 rounded">
            {officer.unit}
          </span>
          <span className="text-[10px] font-medium text-slate-400 uppercase">
            {officer.category}
          </span>
        </div>

        <h3 className="text-lg font-bold text-slate-900 leading-tight mb-1 group-hover:text-blue-700 transition-colors">
          {officer.name}
        </h3>

        <div className="flex items-center gap-2 mb-4">
          <span className="text-sm font-semibold text-slate-700">{officer.rank}</span>
          <span className="text-slate-300">•</span>
          <span className="text-sm text-slate-500 italic">{officer.role}</span>
        </div>

        <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-100">
          <div className="flex flex-col">
            <span className="text-[10px] uppercase text-slate-400 font-semibold">Contato</span>
            <span className="text-base font-mono font-bold text-slate-800">{officer.contact}</span>
          </div>

          <div className="flex gap-2">
             <button 
              onClick={handleWhatsApp}
              className="p-2.5 rounded-full bg-green-50 text-green-600 hover:bg-green-600 hover:text-white transition-all shadow-sm"
              title="WhatsApp"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/></svg>
            </button>
            <button 
              onClick={handleCall}
              className="p-2.5 rounded-full bg-blue-50 text-blue-600 hover:bg-blue-600 hover:text-white transition-all shadow-sm"
              title="Ligar"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/></svg>
