import React, { useState, useMemo } from 'react';
import { CATEGORIES, OFFICER_DATA } from './data';
import OfficerCard from './components/OfficerCard';

const App: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeCategory, setActiveCategory] = useState('all');

  const filteredOfficers = useMemo(() => {
    return OFFICER_DATA.filter((officer) => {
      const matchesSearch = 
        officer.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        officer.unit.toLowerCase().includes(searchTerm.toLowerCase()) ||
        officer.role?.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesCategory = activeCategory === 'all' || officer.category === activeCategory;

      return matchesSearch && matchesCategory;
    });
  }, [searchTerm, activeCategory]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="container mx-auto px-4 py-6">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
              <div className="flex items-center gap-3 mb-1">
                <div className="w-10 h-10 bg-white rounded-lg flex items-center justify-center text-slate-900 font-black text-xl shadow-inner">
                  PM
                </div>
                <div>
                  <h1 className="text-xl md:text-2xl font-black tracking-tight uppercase">PMAL</h1>
                  <p className="text-xs text-slate-400 font-medium tracking-wide">Comandantes e Diretores</p>
                </div>
              </div>
            </div>

            <div className="relative flex-1 max-w-xl">
              <span className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-slate-500">
                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
              </span>
              <input
                type="text"
                placeholder="Buscar por nome, unidade ou cargo..."
                className="w-full pl-10 pr-4 py-3 bg-slate-800 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
              {searchTerm && (
                <button 
                  onClick={() => setSearchTerm('')}
                  className="absolute inset-y-0 right-0 flex items-center pr-3 text-slate-500 hover:text-white"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
                </button>
              )}
            </div>
          </div>
        </div>

        {/* Categories Bar */}
        <div className="border-t border-slate-800 bg-slate-900/50 backdrop-blur-md overflow-x-auto no-scrollbar">
          <div className="container mx-auto px-4 flex gap-2 py-3">
            {CATEGORIES.map((cat) => (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(cat.id)}
                className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-semibold transition-all ${
                  activeCategory === cat.id
                    ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20'
                    : 'bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-slate-200'
                }`}
              >
                <span>{cat.icon}</span>
                {cat.label}
              </button>
            ))}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8 flex-1">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            Resultados
            <span className="bg-slate-200 text-slate-600 text-xs px-2 py-0.5 rounded-full font-bold">
              {filteredOfficers.length}
            </span>
          </h2>
          {activeCategory !== 'all' && (
             <button 
               onClick={() => setActiveCategory('all')}
               className="text-sm text-blue-600 font-semibold hover:underline"
             >
               Limpar filtros
             </button>
          )}
        </div>

        {filteredOfficers.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredOfficers.map((officer) => (
              <OfficerCard key={officer.id} officer={officer} />
            ))}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-20 text-center">
            <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400">
              <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            </div>
            <h3 className="text-lg font-bold text-slate-800">Nenhum oficial encontrado</h3>
            <p className="text-slate-500 max-w-xs">Tente ajustar sua busca ou mudar a categoria selecionada.</p>
            <button 
              onClick={() => {setSearchTerm(''); setActiveCategory('all');}}
              className="mt-6 text-blue-600 font-bold px-6 py-2 border-2 border-blue-600 rounded-lg hover:bg-blue-50 transition-colors"
            >
              Resetar Tudo
            </button>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-8">
        <div className="container mx-auto px-4 text-center">
          <p className="text-slate-400 text-sm font-medium">
            PMAL - Guia de Contatos Institucionais
          </p>
          <p className="text-slate-300 text-[10px] mt-1 uppercase tracking-widest font-bold">
            Uso estritamente profissional
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

